// ⭐ Starfish Blink — 6 LEDs all on Pin 8
// Shape:
//
//         [Top Arm]
//    [LUp]  [Center]  [RUp]
//    [LDn]            [RDn]
//
// 1 Center LED + 5 Arm tip LEDs = Starfish!

const int LED_PIN = 8;

void setup() {
  pinMode(LED_PIN, OUTPUT);
}

void loop() {
  // All LEDs ON — starfish glows!
  digitalWrite(LED_PIN, HIGH);
  delay(600);

  // All LEDs OFF
  digitalWrite(LED_PIN, LOW);
  delay(400);
}

