// ⭐ Starfish Blink — Button Triggered
// Shape:
//
//         [Top Arm]
//    [LUp]  [Center]  [RUp]
//    [LDn]            [RDn]
//
// Press the button to toggle the starfish blink ON/OFF!
// Button on D2 (INPUT_PULLUP) — press = LOW

const int LED_PIN    = 8;
const int BUTTON_PIN = 2;

bool blinking       = false;   // is starfish active?
bool lastButtonState = HIGH;   // previous button reading
bool ledsOn         = false;   // current LED state

unsigned long lastBlinkTime = 0;
const unsigned long ON_TIME  = 600;
const unsigned long OFF_TIME = 400;

void setup() {
  pinMode(LED_PIN,    OUTPUT);
  pinMode(BUTTON_PIN, INPUT_PULLUP);
  digitalWrite(LED_PIN, LOW);
}

void loop() {
  // --- Button toggle detection ---
  bool currentButton = digitalRead(BUTTON_PIN);
  if (lastButtonState == HIGH && currentButton == LOW) {
    // Button just pressed — toggle blink mode
    blinking = !blinking;
    if (!blinking) {
      // Turn off all LEDs immediately when stopped
      digitalWrite(LED_PIN, LOW);
      ledsOn = false;
    }
    delay(50); // debounce
  }
  lastButtonState = currentButton;

  // --- Non-blocking blink ---
  if (blinking) {
    unsigned long now = millis();
    unsigned long interval = ledsOn ? ON_TIME : OFF_TIME;
    if (now - lastBlinkTime >= interval) {
      ledsOn = !ledsOn;
      digitalWrite(LED_PIN, ledsOn ? HIGH : LOW);
      lastBlinkTime = now;
    }
  }
}

